#include<bits/stdc++.h>
using namespace std;
int dp[2][500010],n,a[500010],pre[500010];
int main()
{
    scanf("%d",&n);
    dp[1][0]=-1e9;
    int max1=0,max2=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        if(a[max1]==a[i])
        {
            dp[1][i]=dp[0][max2]+1;
        }
        else
        {
            dp[1][i]=dp[0][max1]+1;
        }
        dp[0][i]=dp[1][pre[a[i]]]+1;
        pre[a[i]]=i;
        if(dp[0][i]>=dp[0][max1])
        {
            if(a[i]!=a[max1])
            {
                max2=max1;
            }
            max1=i;
        }
        else if(dp[0][i]>=dp[0][max2]&&a[i]!=a[max1])
        {
            max2=i;
        }
        // printf("dp[0][%d]=%d dp[1][%d]=%d max1=%d max2=%d\n",i,dp[0][i],i,dp[1][i],max1,max2);
    }
    printf("%d",dp[0][max1]);
    return 0;
}
